#!/usr/bin/env node
'use strict';

/* Self-contained Java Log Console client installer. */
const fs = require('fs');
const path = require('path');
const zlib = require('zlib');

const PAYLOAD = '';

const UPDATE_PAYLOAD = '';

const SIMPLE_DOWNLOAD_UPDATE_PAYLOAD = '';

function usage() {
  console.log([
    'Usage: node setup-client.js [--dir <directory>] [--force]',
    '',
    'Recreates the complete log-console-client project from this file.',
    'Default output directory: ./log-console-client',
    '',
    'Options:',
    '  --dir <directory>  Write the client project to this directory.',
    '  --force            Overwrite embedded project files if the directory exists.',
  ].join('\n'));
}

function fail(message) {
  console.error('\nSetup failed: ' + message);
  process.exit(1);
}

function readArguments() {
  const options = { directory: path.resolve(process.cwd(), 'log-console-client'), force: false };

  for (let index = 2; index < process.argv.length; index += 1) {
    const argument = process.argv[index];
    if (argument === '--help' || argument === '-h') {
      usage();
      process.exit(0);
    }
    if (argument === '--force') {
      options.force = true;
      continue;
    }
    if (argument === '--dir') {
      const directory = process.argv[index + 1];
      if (!directory || directory.startsWith('--')) {
        fail('--dir requires a directory path.');
      }
      options.directory = path.resolve(process.cwd(), directory);
      index += 1;
      continue;
    }
    fail('unknown option: ' + argument);
  }

  return options;
}

function loadFiles() {
  try {
    const files = JSON.parse(zlib.gunzipSync(Buffer.from(PAYLOAD, 'base64')).toString('utf8'));
    const updates = JSON.parse(zlib.gunzipSync(Buffer.from(UPDATE_PAYLOAD, 'base64')).toString('utf8'));
    const simpleDownloadUpdates = JSON.parse(
      zlib.gunzipSync(Buffer.from(SIMPLE_DOWNLOAD_UPDATE_PAYLOAD, 'base64')).toString('utf8')
    );
    Object.assign(files, updates, simpleDownloadUpdates);
    ["src/main/java/com/example/logconsole/download/ChronologicalMerger.java","src/main/java/com/example/logconsole/download/DownloadCheckpoint.java","src/main/java/com/example/logconsole/download/DownloadStager.java","src/main/java/com/example/logconsole/download/FileRecordReader.java","src/main/java/com/example/logconsole/download/PartWriter.java","src/main/java/com/example/logconsole/download/SourceConcatenator.java","src/main/java/com/example/logconsole/download/StagedSource.java","src/test/java/com/example/logconsole/download/ChronologicalMergerTest.java","src/test/java/com/example/logconsole/download/DownloadStagerTest.java","src/test/java/com/example/logconsole/download/SourceConcatenatorTest.java"].forEach((file) => delete files[file]);
    return files;
  } catch (error) {
    fail('the embedded project payload is invalid: ' + error.message);
  }
}

function extractClient(destination, files, force) {
  if (fs.existsSync(destination) && !force) {
    fail(destination + ' already exists. Choose another --dir or run again with --force.');
  }

  fs.mkdirSync(destination, { recursive: true });
  const prefix = destination + path.sep;

  for (const [relativePath, encodedContent] of Object.entries(files)) {
    const outputPath = path.resolve(destination, relativePath);
    if (!outputPath.startsWith(prefix)) {
      fail('the embedded payload contains an unsafe path.');
    }
    fs.mkdirSync(path.dirname(outputPath), { recursive: true });
    fs.writeFileSync(outputPath, Buffer.from(encodedContent, 'base64'));
  }

  if (process.platform !== 'win32') {
    fs.chmodSync(path.join(destination, 'mvnw'), 0o755);
    fs.chmodSync(path.join(destination, 'bin', 'log-console.sh'), 0o755);
  }
}

const options = readArguments();
const files = loadFiles();

console.log('Extracting ' + Object.keys(files).length + ' client files to ' + options.directory + '...');
extractClient(options.directory, files, options.force);
console.log('\nClient project setup complete. Build it manually from:\n  ' + options.directory);
